  "PopperDefault": {
    "title": "index.html",
    "icon": "html",
    "lang": "html",
    "code": "<div class=\"flex flex-col items-center gap-14\">\n    <div class=\"flex items-center justify-center w-full\">\n        <div\n            data-reference-el\n            class=\"w4/5 max-w80 h30 relative rounded-md flex bg-zinc3 dark-bg-zinc7/50\"\n        >\n        </div>\n    </div>\n    <div\n        data-popper-el\n        class=\"ui-popper p0.5 rounded-md bg-zinc3 dark-bg-zinc-800/70 text-white text-sm b b-zinc6 dark-b-zinc7/40 w46 h7 text-sm flex items-center justify-center text-center\"\n    >\n        Bottom\n    </div>\n    <div class=\"flex flex-wrap justify-center gap3\">\n        <button\n            data-trigger-popper\n            data-set-placement=\"bottom\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Bottom\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"bottom-start\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Bottom-start\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"bottom-end\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Bottom-end\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"top\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Top\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"top-start\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Top-start\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"top-end\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Top-end\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"left\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Left\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"left-start\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Left-start\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"left-end\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Left-end\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"right\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Right\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"right-start\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Right-start\n        </button>\n        <button\n            data-trigger-popper\n            data-set-placement=\"right-end\"\n            class=\"bg-zinc-800 text-white px-4 py-2 rounded-lg text-sm\"\n        >\n            Right-end\n        </button>\n    </div>\n</div>\n\n<script>\n    import { CreatePopper, type Placement } from \"flexipop\";\n\n    const initPopperExample = () => {\n        const triggers = Array.from(\n            document.querySelectorAll(\"[data-trigger-popper]\"),\n        ) as HTMLButtonElement[];\n        const popperEl = document.querySelector(\"[data-popper-el]\");\n        const reference = document.querySelector(\"[data-reference-el]\");\n\n        if (\n            popperEl instanceof HTMLElement &&\n            reference instanceof HTMLElement\n        ) {\n            let currentPosition: Placement = \"bottom\";\n            const popper = new CreatePopper(reference, popperEl, {\n                placement: currentPosition,\n            });\n            popper.updatePosition();\n            for (const trigger of triggers) {\n                trigger.addEventListener(\"click\", () => {\n                    const position = trigger.getAttribute(\n                        \"data-set-placement\",\n                    ) as Placement;\n                    if (position !== currentPosition) {\n                        popperEl.innerHTML = position;\n                        popperEl.style.opacity = \"0\";\n                        // change placment here\n                        popper.setOptions({\n                            placement: position,\n                        });\n                        currentPosition = position;\n                        popperEl.style.opacity = \"1\";\n                    }\n                });\n            }\n        }\n    };\n    initPopperExample();\n    document.addEventListener(\"astro:after-swap\", initPopperExample);\n</script>\n"
  },
